+	flags := &rootFlags{jsonOutput: true}
+	cmd := newDomCmd(flags)
+	cmd.SetArgs([]string{"all", "#x"})
+	_ = cmd.Flags().Set("mode", "text")
+
+	var buf bytes.Buffer
